    %% Intercepts
    \path [regression, black!30] (M#2#3.\i) edge ["\labtau"] (#2#3\j.270);

    %% Residuals
    \node [residual] (e\j) [above right = 4mm of #2#3\j] {$\uptheta_{#3,\num}$};
