The next step is to complete the drawing of the factor: include the factor, a latent variable, positioned above the middle indicator; include the loadings, which are regressions, and I control the angle for the regression arrow to enter the indicator; and include the indicator residuals. The \drawfactor command needs another argument, to take the factor name, POS or NEG.

\documentclass[border = 10pt]{standalone}
\input{SEMstyles.tex}

\newcommand {\drawfactor} [3] {
                           %  #1 pos or neg indicator
                           %  #2 POS or NEG factor
                           %  #3 position of 1st imdicator

  %% Indicators
  \node [manifest] (#11) [#3] {$#1_1$};
  \node [manifest] (#12) [right = 1cm of #11] {$#1_2$};
  \node [manifest] (#13) [right = 1cm of #12] {$#1_3$};

  %% Factor
  \node [latent] (#2) [above = 2cm of #12] {#2};

  %% Loadings
  \path [regression] 
    (#2) edge (#11.90)
    (#2) edge (#12.90)
    (#2) edge (#13.90);  

  %% Residuals  
  \node [residual] (e1) [below right = 4mm of #11] {};
  \node [residual] (e2) [below right = 4mm of #12] {};
  \node [residual] (e3) [below right = 4mm of #13] {};  

  \path [regression] 
    (e1) edge (#11.south east)
    (e2) edge (#12.south east)
    (e3) edge (#13.south east);
}

\begin{document}
\begin{tikzpicture}

\drawfactor{pos}{POS}{}
\drawfactor{neg}{NEG}{right = 2cm of pos3}

\end{tikzpicture} 
\end{document} 


The commands to position the loadings and residuals involve repetition. There might be some benefit to positioning them in a \foreach loop.

\documentclass[border = 10pt]{standalone}
\input{SEMstyles.tex}

\newcommand {\drawfactor} [3] {    
                           %  #1 pos or neg indicator 
                           %  #2 POS or NEG factor 
                           %  #3 position 1st indicator
  %% Indicators
  \node [manifest] (#11) [#3] {$#1_1$};
  \node [manifest] (#12) [right = 1cm of #11] {$#1_2$};
  \node [manifest] (#13) [right = 1cm of #12] {$#1_3$};

  %% Factor
  \node [latent] (#2) [above = 2cm of #12] {#2};

  \foreach \i in {1,2,3} {
    %% Loadings  
    \path [regression] (#2) edge (#1\i.90);

    %% Residuals
    \node [residual] (e\i) [below right = 4mm of #1\i] {};
    \path [regression] (e\i) edge (#1\i.south east);
  }
}

